import{c as t,Q as n,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse(`{"title":"What Is Harness Engineering: A New Concept Defining the 'Outside' of Context Engineering","description":"","frontmatter":{"title":"What Is Harness Engineering: A New Concept Defining the 'Outside' of Context Engineering","date":"2026-02-20T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-02-20-harness-engineering-overview-smartscope.md","filePath":"research/ai-articles/scored/2026-02-20-harness-engineering-overview-smartscope.md","lastUpdated":1779796674000}`),s={name:"research/ai-articles/scored/2026-02-20-harness-engineering-overview-smartscope.md"};function i(o,e,l,d,h,c){return n(),r("div",null,[...e[0]||(e[0]=[a('<blockquote><p>Source: <a href="https://smartscope.blog/en/blog/harness-engineering-overview/" target="_blank" rel="noreferrer">https://smartscope.blog/en/blog/harness-engineering-overview/</a> Fetched: 2026-05-08</p></blockquote><h1 id="what-is-harness-engineering-a-new-concept-defining-the-outside-of-context-engineering" tabindex="-1">What Is Harness Engineering: A New Concept Defining the &#39;Outside&#39; of Context Engineering <a class="header-anchor" href="#what-is-harness-engineering-a-new-concept-defining-the-outside-of-context-engineering" aria-label="Permalink to &quot;What Is Harness Engineering: A New Concept Defining the &#39;Outside&#39; of Context Engineering&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Harness engineering represents a framework for ensuring AI agent quality through environmental design mechanisms rather than prompt optimization alone. The concept emerged in February 2026 as a distinct discipline addressing failures that cannot be prevented through improved prompts or context alone.</p><h2 id="problems-prompts-cannot-prevent" tabindex="-1">Problems Prompts Cannot Prevent <a class="header-anchor" href="#problems-prompts-cannot-prevent" aria-label="Permalink to &quot;Problems Prompts Cannot Prevent&quot;">​</a></h2><p>LLM agents exhibit characteristic failure modes that resist traditional prompt-based solutions. These include writing code that violates architectural dependencies, relying on outdated repository information, circumventing linting rules rather than fixing underlying issues, and declaring tasks complete without verification. As one source notes, &quot;they cannot be structurally prevented no matter how much you improve prompts or context.&quot;</p><h2 id="defining-harness-engineering" tabindex="-1">Defining Harness Engineering <a class="header-anchor" href="#defining-harness-engineering" aria-label="Permalink to &quot;Defining Harness Engineering&quot;">​</a></h2><p>Harness engineering is &quot;environment design that ensures agent output quality through mechanisms rather than prompts.&quot; The term draws from horse-tack equipment, suggesting the complete apparatus needed to channel unpredictable yet powerful agents productively. This encompasses linters, hooks, CI pipelines, and information freshness management—the entire system operating outside the LLM itself.</p><h2 id="quantified-performance-impact" tabindex="-1">Quantified Performance Impact <a class="header-anchor" href="#quantified-performance-impact" aria-label="Permalink to &quot;Quantified Performance Impact&quot;">​</a></h2><p>Experimental evidence demonstrates dramatic improvements from harness changes alone:</p><ul><li><strong>Can.ac&#39;s experiment</strong>: A single model&#39;s performance jumped from 6.7% to 68.3% (approximately 10x improvement) by changing tool formatting—with no model weights modified.</li><li><strong>LangChain&#39;s Terminal Bench 2.0</strong>: Harness optimization alone improved rankings from 30th to 5th place with identical underlying models.</li></ul><h2 id="openai-s-one-million-line-case-study" tabindex="-1">OpenAI&#39;s One-Million-Line Case Study <a class="header-anchor" href="#openai-s-one-million-line-case-study" aria-label="Permalink to &quot;OpenAI&#39;s One-Million-Line Case Study&quot;">​</a></h2><p>OpenAI&#39;s February 2026 practical report documented building approximately one million lines of code entirely through agent generation across five months. Key principles derived include:</p><ol><li><strong>Design the environment, not the code</strong> – Engineer prerequisite conditions rather than manually intervening</li><li><strong>Enforce architecture mechanically</strong> – Use custom linters and structural tests to prevent violations automatically</li><li><strong>Make repositories the single source of truth</strong> – Place all knowledge in version-controlled artifacts</li><li><strong>Connect observability to agents</strong> – Enable measurement of actual outcomes</li><li><strong>Fight entropy</strong> – Automate cleanup tasks rather than manual maintenance</li></ol><h2 id="the-four-quadrants-of-harness-design" tabindex="-1">The Four Quadrants of Harness Design <a class="header-anchor" href="#the-four-quadrants-of-harness-design" aria-label="Permalink to &quot;The Four Quadrants of Harness Design&quot;">​</a></h2><p>Harness engineering spans four interconnected domains:</p><table tabindex="0"><thead><tr><th>Quadrant</th><th>Focus</th><th>Implementation</th></tr></thead><tbody><tr><td>Architecture constraints</td><td>What to prevent</td><td>Linters, dependency rules</td></tr><tr><td>Feedback loops</td><td>What to measure</td><td>CI/CD, observability</td></tr><tr><td>Workflow control</td><td>How to run</td><td>Task splitting, permissions</td></tr><tr><td>Improvement cycles</td><td>How to sustain</td><td>Entropy management, document freshness</td></tr></tbody></table><p>Feedback speed proves critical—PostToolUse hooks (milliseconds) execute far faster than human review (hours/days), enabling immediate agent self-correction.</p><h2 id="relationship-between-prompt-context-and-harness" tabindex="-1">Relationship Between Prompt, Context, and Harness <a class="header-anchor" href="#relationship-between-prompt-context-and-harness" aria-label="Permalink to &quot;Relationship Between Prompt, Context, and Harness&quot;">​</a></h2><p>These three engineering disciplines form a nested hierarchy: &quot;Harness ⊇ Context ⊇ Prompt.&quot;</p><ul><li><strong>Prompts</strong> optimize individual LLM instructions</li><li><strong>Context</strong> optimizes everything the LLM observes</li><li><strong>Harness</strong> optimizes the complete operational system</li></ul><p>Using a computing analogy: if the model is the CPU, the harness functions as the operating system. The distinction matters: context engineering addresses &quot;what to show,&quot; while harness engineering addresses &quot;what to prevent, measure, and control.&quot;</p><h2 id="harness-integration-for-coding-agents" tabindex="-1">Harness Integration for Coding Agents <a class="header-anchor" href="#harness-integration-for-coding-agents" aria-label="Permalink to &quot;Harness Integration for Coding Agents&quot;">​</a></h2><p>Claude Code users can design several harness components:</p><ul><li><strong>CLAUDE.md</strong> – Aggregates repository knowledge</li><li><strong>Commands</strong> – Enables reproducible task execution</li><li><strong>Hooks</strong> – Automate processing at specific events</li><li><strong>Permissions</strong> – Define auto-approval scope</li><li><strong>Skills and MCP servers</strong> – Extend capabilities (context layer)</li></ul><p>A minimal PostToolUse hook example runs linters automatically on file writes, enabling immediate feedback.</p><h2 id="diagnostic-heuristic" tabindex="-1">Diagnostic Heuristic <a class="header-anchor" href="#diagnostic-heuristic" aria-label="Permalink to &quot;Diagnostic Heuristic&quot;">​</a></h2><p><strong>Context layer problems</strong>: Individual outputs miss targets; necessary information isn&#39;t referenced.</p><p><strong>Harness layer problems</strong>: Outputs vary across repeated use; architectural consistency degrades; previous fixes get ignored.</p><h2 id="implementation-considerations" tabindex="-1">Implementation Considerations <a class="header-anchor" href="#implementation-considerations" aria-label="Permalink to &quot;Implementation Considerations&quot;">​</a></h2><p>When multiple agents operate in parallel, harness design becomes increasingly critical. Teams separate directories by domain boundaries and employ dependency-analysis tools in CI to prevent architectural violations automatically. What feels cumbersome for humans suits parallel agent workflows perfectly.</p><h2 id="critical-perspectives" tabindex="-1">Critical Perspectives <a class="header-anchor" href="#critical-perspectives" aria-label="Permalink to &quot;Critical Perspectives&quot;">​</a></h2><p>The term remains fluid one month after emergence. Criticism includes:</p><ul><li>The &quot;harness&quot; metaphor potentially misrepresents agent autonomy</li><li>Complexity often trends toward unnecessary over-engineering</li><li>Successful implementations show progression toward <em>simplification</em>, not elaboration</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Harness engineering addresses the problem structure: certain quality issues cannot be solved through improved prompts, and sustained system quality requires mechanisms beyond context optimization. The discipline encompasses constraint enforcement, measurement systems, workflow design, and entropy management—the infrastructure enabling reliable agent operation at scale.</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心定義-prompt-無法解決的問題" tabindex="-1">核心定義：Prompt 無法解決的問題 <a class="header-anchor" href="#核心定義-prompt-無法解決的問題" aria-label="Permalink to &quot;核心定義：Prompt 無法解決的問題&quot;">​</a></h3><p>Harness engineering 是「<strong>透過機制而非 prompt 來確保 Agent 輸出品質的環境設計</strong>」。某些失敗模式——寫違反架構依賴的程式碼、仰賴過時 repo 資訊、規避 linting 規則而非修復根本、未驗證就宣告完成——無論如何改善 prompt 都無法從結構上預防。</p><p>術語來自馬具（horse-tack），暗示引導不可預測但強大的 agent 所需的完整裝置：linter、hooks、CI pipeline、資訊新鮮度管理。</p><h3 id="量化效能衝擊" tabindex="-1">量化效能衝擊 <a class="header-anchor" href="#量化效能衝擊" aria-label="Permalink to &quot;量化效能衝擊&quot;">​</a></h3><table tabindex="0"><thead><tr><th>案例</th><th>結果</th></tr></thead><tbody><tr><td><strong>Can.ac 實驗</strong></td><td>僅改變工具格式，同一模型從 <strong>6.7% → 68.3%</strong>（約 10 倍改進），未修改任何模型權重</td></tr><tr><td><strong>LangChain TerminalBench 2.0</strong></td><td>僅優化 harness，相同模型排名從<strong>第 30 → 第 5</strong>（不換模型）</td></tr></tbody></table><h3 id="openai-百萬行案例-五大設計原則" tabindex="-1">OpenAI 百萬行案例：五大設計原則 <a class="header-anchor" href="#openai-百萬行案例-五大設計原則" aria-label="Permalink to &quot;OpenAI 百萬行案例：五大設計原則&quot;">​</a></h3><p>OpenAI 2026 年 2 月報告（五個月、純 Agent 生成約百萬行程式碼）萃取出：</p><ol><li><strong>設計環境，不寫程式碼</strong>：工程前置條件，而非手動介入</li><li><strong>機械強制架構</strong>：用自訂 linter 和結構測試自動防止違規</li><li><strong>讓 Repo 成為單一真相來源</strong>：所有知識放在版本控制的 artifact</li><li><strong>連接可觀測性到 Agent</strong>：讓實際結果可量測</li><li><strong>對抗熵</strong>：自動化清理任務，而非手動維護</li></ol><h3 id="四象限-harness-設計框架" tabindex="-1">四象限 Harness 設計框架 <a class="header-anchor" href="#四象限-harness-設計框架" aria-label="Permalink to &quot;四象限 Harness 設計框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th>象限</th><th>焦點</th><th>實作方式</th></tr></thead><tbody><tr><td><strong>架構約束</strong></td><td>預防什麼</td><td>Linter、依賴規則</td></tr><tr><td><strong>反饋循環</strong></td><td>量測什麼</td><td>CI/CD、可觀測性</td></tr><tr><td><strong>工作流控制</strong></td><td>如何執行</td><td>任務拆分、權限</td></tr><tr><td><strong>改進週期</strong></td><td>如何持續</td><td>熵管理、文件新鮮度</td></tr></tbody></table><p>反饋速度至關重要：<strong>PostToolUse hooks（毫秒）遠快於人工 review（小時/天）</strong>，讓 Agent 能立即自我修正。</p><h3 id="三層嵌套關係" tabindex="-1">三層嵌套關係 <a class="header-anchor" href="#三層嵌套關係" aria-label="Permalink to &quot;三層嵌套關係&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Harness ⊇ Context ⊇ Prompt</span></span></code></pre></div><ul><li><strong>Prompt</strong>：優化單次 LLM 指令</li><li><strong>Context</strong>：優化 LLM 觀察到的一切</li><li><strong>Harness</strong>：優化完整的操作系統</li></ul><p>以計算機類比：模型是 CPU，harness 是作業系統。Context engineering 解決「展示什麼」；harness engineering 解決「預防什麼、量測什麼、控制什麼」。</p><h3 id="診斷啟發法" tabindex="-1">診斷啟發法 <a class="header-anchor" href="#診斷啟發法" aria-label="Permalink to &quot;診斷啟發法&quot;">​</a></h3><ul><li><strong>Context 層問題</strong>：個別輸出錯過目標；必要資訊未被參照</li><li><strong>Harness 層問題</strong>：重複使用時輸出變異；架構一致性降解；先前修復被忽略</li></ul><h3 id="claude-code-的-harness-組件" tabindex="-1">Claude Code 的 Harness 組件 <a class="header-anchor" href="#claude-code-的-harness-組件" aria-label="Permalink to &quot;Claude Code 的 Harness 組件&quot;">​</a></h3><p>CLAUDE.md（彙整 repo 知識）→ Commands（可重現任務執行）→ Hooks（特定事件自動化）→ Permissions（定義自動核准範圍）→ Skills + MCP servers（擴充能力）</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>4 象限框架可直接指導 cc-workspace harness 設計；PostToolUse vs 人工審查對比實用</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>4 象限分類（Architecture/Feedback/Workflow/Improvement）原創合成</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>Can.ac 6.7%→68.3%（10x）、LangChain 30th→5th，有名有數的實驗</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>廣度佳但每象限深度有限；缺乏實作範例</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>4 象限框架跨 agent 平台和語言通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.05/10</strong></td><td>8×0.3+8×0.2+9×0.2+7×0.15+8×0.15 = 2.4+1.6+1.8+1.05+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（4 象限框架）<br><strong>整合狀態</strong>：待實作</p>',61)])])}const m=t(s,[["render",i]]);export{p as __pageData,m as default};
